const DashboardSidebar = ({ me, onMobileClose, openMobile }) => {
  const {
    firstname = '',
    lastname = '',
    department: { name: departmentName = '' } = {},
  } = JSON.parse(getStorage('remember') || '{}');

  const { handleSignout } = useContext(PassportAuth);
  const history = useHistory();
  const location = useLocation();
  const [activeModuleName, setActiveModuleName] = React.useState('');

  const onSignOut = async () => {
    await handleSignout();
    history.push('/login');
  };

  useEffect(() => {
    if (openMobile && onMobileClose) {
      onMobileClose();
    }
  }, [location.pathname]);

  const moduleGroups = React.useMemo(() => {
    const groups = {};
    items.forEach((item) => {
      if (accessRight(me, item.name)) {
        if (!groups[item.name]) {
          groups[item.name] = {
            name: item.name,
            title: item.title,
            icon: item.icon,
            href: item.href,
            items: [],
          };
        }
        groups[item.name].items.push(item);
      }
    });
    return Object.values(groups);
  }, [me]);

  useEffect(() => {
    const found = moduleGroups.find((m) =>
      m.items.some(
        (item) =>
          location.pathname.startsWith(item.href) ||
          (item?.sub &&
            item.sub.some((s) => location.pathname.startsWith(s.href))),
      ),
    );
    if (found) {
      setActiveModuleName(found.name);
    } else if (moduleGroups.length > 0 && !activeModuleName) {
      setActiveModuleName(moduleGroups[0].name);
    }
  }, [location.pathname, moduleGroups]);

  const activeGroup = moduleGroups.find((m) => m.name === activeModuleName);

  const content = (
    <Box
      sx={{
        display: 'flex',
        height: '100%',
        backgroundColor: 'background.paper',
        overflow: 'hidden',
        boxShadow: '4px 0 24px rgba(0,0,0,0.05)',
      }}
    >
      {/* Primary Rail (Icons) */}
      <Box
        sx={{
          width: 80,
          backgroundColor: '#1e1b4b', // Dark Indigo 900
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          py: 3,
          zIndex: 10,
          boxShadow: '4px 0 10px rgba(0,0,0,0.1)',
        }}
      >
        <Box sx={{ mb: 4 }}>
          <Avatar
            sx={{
              width: 48,
              height: 48,
              cursor: 'pointer',
              border: '2px solid rgba(255,255,255,0.2)',
              transition: 'transform 0.2s',
              '&:hover': { transform: 'scale(1.05)', borderColor: '#fff' },
            }}
            src={me?.userData?.image?.url}
            alt={firstname}
          />
        </Box>
        <Box
          sx={{
            flexGrow: 1,
            display: 'flex',
            flexDirection: 'column',
            gap: 2,
            overflowY: 'auto',
            width: '100%',
            alignItems: 'center',
            '::-webkit-scrollbar': { display: 'none' },
          }}
        >
          {moduleGroups.map((mod) => (
            <Tooltip key={mod.name} title={mod.title} placement="right" arrow>
              <Box
                onClick={() => {
                  setActiveModuleName(mod.name);
                  history.push(mod.href);
                }}
                sx={{
                  p: 1.5,
                  borderRadius: '16px',
                  cursor: 'pointer',
                  color:
                    activeModuleName === mod.name
                      ? '#fff'
                      : 'rgba(255, 255, 255, 0.4)',
                  backgroundColor:
                    activeModuleName === mod.name
                      ? '#4f46e5' // Indigo 500
                      : 'transparent',
                  boxShadow:
                    activeModuleName === mod.name
                      ? '0 4px 12px rgba(79, 70, 229, 0.4)'
                      : 'none',
                  transition: 'all 0.2s ease',
                  '&:hover': {
                    backgroundColor: 'rgba(255, 255, 255, 0.1)',
                    color: '#fff',
                    transform: 'translateY(-2px)',
                  },
                  display: 'flex',
                  justifyContent: 'center',
                  alignItems: 'center',
                  width: 50,
                  height: 50,
                }}
              >
                <mod.icon size={22} />
              </Box>
            </Tooltip>
          ))}
        </Box>
        <Divider
          sx={{ width: '40%', my: 2, borderColor: 'rgba(255,255,255,0.1)' }}
        />
        <Tooltip title="Sign Out" placement="right">
          <Box
            onClick={onSignOut}
            sx={{
              p: 1.5,
              cursor: 'pointer',
              color: 'rgba(255, 255, 255, 0.5)',
              transition: 'color 0.2s',
              '&:hover': { color: '#ef4444' }, // Red hover
            }}
          >
            <i
              className="fas fa-sign-out-alt"
              style={{ fontSize: '1.4rem' }}
            ></i>
          </Box>
        </Tooltip>
      </Box>

      {/* Secondary Rail (Submenu) */}
      <Box
        sx={{
          width: 240,
          display: 'flex',
          flexDirection: 'column',
          backgroundColor: '#fff', // White background
          borderRight: '1px solid rgba(0, 0, 0, 0.05)',
        }}
      >
        <Box sx={{ p: 3, pb: 2 }}>
          <Typography
            variant="h6"
            color="primary.dark"
            sx={{ fontWeight: 700, letterSpacing: 0.5 }}
          >
            {activeGroup?.title || 'Menu'}
          </Typography>
          <Typography variant="caption" color="text.secondary">
            {departmentName}
          </Typography>
        </Box>
        <Divider sx={{ mb: 1, mx: 3 }} />
        <Box sx={{ flexGrow: 1, overflowY: 'auto', px: 2, pb: 2 }}>
          <List disablePadding>
            {(activeGroup?.items || [])
              .reduce((acc, item) => {
                if (item.sub && item.sub.length > 0) {
                  item.sub.forEach((subItem) => {
                    if (accessRight(me, item.name, subItem.level)) {
                      // Pass parent's moduleName to subItem for context if needed
                      acc.push({ ...subItem, moduleName: item.name });
                    }
                  });
                } else {
                  acc.push({ ...item, moduleName: item.name });
                }
                return acc;
              }, [])
              .map((item, index) => (
                <div key={item.title + index}>
                  <NavItem
                    href={item.href}
                    title={item.title}
                    icon={item.icon}
                    sub={item.sub}
                    me={me}
                    moduleName={item.moduleName}
                  />
                </div>
              ))}
          </List>
        </Box>
      </Box>
    </Box>
  );

  return (
    <div>
      <Hidden lgUp>
        <Drawer
          anchor="left"
          onClose={onMobileClose}
          open={openMobile}
          variant="temporary"
          PaperProps={{
            sx: {
              width: 320, // Increased width for double rail
              border: 'none',
            },
          }}
        >
          {content}
        </Drawer>
      </Hidden>
      <Hidden lgDown>
        <Drawer
          anchor="left"
          open
          variant="persistent"
          PaperProps={{
            sx: {
              width: 320, // Increased width for double rail
              border: 'none',
              height: '100vh',
              top: 0,
            },
          }}
        >
          {content}
        </Drawer>
      </Hidden>
    </div>
  );
};

DashboardSidebar.propTypes = {
  onMobileClose: PropTypes.func,
  openMobile: PropTypes.bool,
  me: PropTypes.object,
};

DashboardSidebar.defaultProps = {
  onMobileClose: () => {},
  openMobile: false,
};

export default DashboardSidebar;
